module RefModule(input            clk,
              input            rst_n,
              input            in,
              output reg [5:0] q
              );  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk, negedge rst_n or posedge dbg_halt) 
     if (!rst_n) 
       q = 0;
     else 
       q <= q << 1 | in;

endmodule
